import pandas as pd
import matplotlib.pyplot as plt
import numpy as np

# Load the full results from the CSV file generated by the main function
df = pd.read_csv('results/all_results.csv')

# Compute selectivity: Assume 'filter' column represents a parameter
# If 'rows_after_filter' and 'total_rows' exist, use them; otherwise, assume 'filter' is selectivity
if 'rows_after_filter' in df.columns and 'total_rows' in df.columns:
    df['selectivity'] = np.round(df['rows_after_filter'] / df['total_rows'], 3)
else:
    # Assume 'filter' values are selectivity ratios or map them to [0,1]
    # If 'filter' is not in [0,1], normalize or adjust based on domain knowledge
    df['selectivity'] = np.round(df['filter'] / df['filter'].max(), 3)  # Example normalization
    
# Define the columns to average
average_columns = ["4_recall", "4_runtime", "8_recall", "8_runtime", "16_recall", "16_runtime"]

# Compute averages by grouping over 'selectivity' and 'k'
averages = df.groupby(['selectivity', 'k', 'ef'])[average_columns].mean().reset_index()

# Add throughput columns (queries per second = 1 / runtime)
for m in [4, 8, 16]:
    averages[f'{m}_throughput'] = 1 / averages[f'{m}_runtime']

# Compute average recall and throughput over m for each row
averages['avg_recall'] = averages[['4_recall', '8_recall', '16_recall']].mean(axis=1)
averages['avg_throughput'] = averages[['4_throughput', '8_throughput', '16_throughput']].mean(axis=1)

# Plot 1: Throughput vs Recall for each m
plt.figure(figsize=(10, 6))
for m in [4, 8, 16]:
    grouped = averages.groupby('k').agg({
        f'{m}_recall': 'mean',
        f'{m}_throughput': 'mean'
    }).reset_index()
    grouped = grouped.sort_values(by='k')  # Sort by k to form a curve
    plt.plot(grouped[f'{m}_recall'], grouped[f'{m}_throughput'], marker='o', label=f'm={m}')
plt.xlabel('Recall')
plt.ylabel('Throughput (queries per second)')
plt.title('Throughput vs Recall for Different m')
plt.legend()
plt.grid(True)
plt.savefig('analysis/plots/throughput_vs_recall.png')
plt.close()

